stage3_refined_code:
from dataclasses import dataclass
from typing import List

@dataclass
class CacheConfiguration:
    name: str
    backups: int
    atomicity_mode: str

@dataclass
class IgniteConfiguration:
    cache_configurations: List[CacheConfiguration]
    discovery_spi: str

def create_cache_configuration(name: str, backups: int, atomicity_mode: str) -> CacheConfiguration:
    return CacheConfiguration(name=name, backups=backups, atomicity_mode=atomicity_mode)

def create_ignite_configuration(cache_configurations: List[CacheConfiguration], discovery_spi: str) -> IgniteConfiguration:
    return IgniteConfiguration(cache_configurations=cache_configurations, discovery_spi=discovery_spi)

def main() -> None:
    cache_config = create_cache_configuration("exampleCache", 1, "ATOMIC")
    ignite_config = create_ignite_configuration([cache_config], "TcpDiscoverySpi")
    print(f"Cache Name: {ignite_config.cache_configurations[0].name}")
    print(f"Backups: {ignite_config.cache_configurations[0].backups}")
    print(f"Atomicity Mode: {ignite_config.cache_configurations[0].atomicity_mode}")
    print(f"Discovery SPI: {ignite_config.discovery_spi}")

if __name__ == "__main__":
    main()
